mapper.select:
SELECT e.emp_id, e.emp_name, e.dept_id, COALESCE(d.dept_name, e.dept_name) AS dept_name, e.position, e.hire_date, e.email, e.phone, e.status, e.created_at, e.updated_at FROM employees e LEFT JOIN departments d ON e.dept_id = d.dept_id
AND e.emp_name LIKE CONCAT('%', #{empName}, '%')
AND e.dept_id = #{deptCode}
AND e.hire_date >= #{hireStartDate}
AND e.hire_date <= #{hireEndDate}
AND e.status = #{status}
ORDER BY e.emp_id

